import{_ as l,o as t,c as e,a2 as i}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 商人流玩法全攻略：不打仗也能稱霸","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/merchant-playthrough.md","filePath":"bannerlord/merchant-playthrough.md"}'),r={name:"bannerlord/merchant-playthrough.md"};function h(o,a,d,n,s,u){return t(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="騎砍2-商人流玩法全攻略-不打仗也能稱霸" tabindex="-1">騎砍2 | 商人流玩法全攻略：不打仗也能稱霸 <a class="header-anchor" href="#騎砍2-商人流玩法全攻略-不打仗也能稱霸" aria-label="Permalink to &quot;騎砍2 | 商人流玩法全攻略：不打仗也能稱霸&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>誰說騎砍一定要打仗？商人流——不打仗、不攻城、不建國，純靠經濟手段致富，甚至可以用錢買下整個卡拉迪亞。</p><hr><h2 id="一、商人流核心理念" tabindex="-1">一、商人流核心理念 <a class="header-anchor" href="#一、商人流核心理念" aria-label="Permalink to &quot;一、商人流核心理念&quot;">​</a></h2><ul><li>不打仗 = 不死兵 = 不會被俘 = 無風險</li><li>錢可以買工廠、買商隊、買裝備、買傭兵</li><li>到後期你富可敵國，想打仗隨時可以轉型</li></ul><hr><h2 id="二、角色創建" tabindex="-1">二、角色創建 <a class="header-anchor" href="#二、角色創建" aria-label="Permalink to &quot;二、角色創建&quot;">​</a></h2><table tabindex="0"><thead><tr><th>選項</th><th style="text-align:center;">推薦</th><th>原因</th></tr></thead><tbody><tr><td>文化</td><td style="text-align:center;">阿塞萊</td><td>貿易懲罰 -10%</td></tr><tr><td>出身</td><td style="text-align:center;">商人</td><td>起始 2000 金 + 交易技能</td></tr><tr><td>屬性</td><td style="text-align:center;">社交 &gt; 智力 &gt; 耐力</td><td>交易 + 管理學</td></tr></tbody></table><hr><h2 id="三、賺錢路線" tabindex="-1">三、賺錢路線 <a class="header-anchor" href="#三、賺錢路線" aria-label="Permalink to &quot;三、賺錢路線&quot;">​</a></h2><h3 id="_3-1-前期-0-30-天" tabindex="-1">3.1 前期（0-30 天） <a class="header-anchor" href="#_3-1-前期-0-30-天" aria-label="Permalink to &quot;3.1 前期（0-30 天）&quot;">​</a></h3><ol><li>競技場賺第一筆錢</li><li>跑腿送貨任務累積資金</li><li>開始跑穀物線（南帝國 → 北帝國）</li></ol><h3 id="_3-2-中期-30-100-天" tabindex="-1">3.2 中期（30-100 天） <a class="header-anchor" href="#_3-2-中期-30-100-天" aria-label="Permalink to &quot;3.2 中期（30-100 天）&quot;">​</a></h3><ol><li>第一座工廠：達努斯蒂卡釀酒廠（8000 金）</li><li>跑商環線穩定收入</li><li>累積到 50000 金 → 買第二座工廠</li><li>組第一個商隊（15000 金）</li></ol><h3 id="_3-3-後期-100-天" tabindex="-1">3.3 後期（100 天+） <a class="header-anchor" href="#_3-3-後期-100-天" aria-label="Permalink to &quot;3.3 後期（100 天+）&quot;">​</a></h3><ol><li>擁有 5+ 工廠 + 3+ 商隊</li><li>日被動收入 3000-5000 金</li><li>錢多到可以買下任何城鎮（跟領主交易）</li></ol><hr><h2 id="四、安全策略" tabindex="-1">四、安全策略 <a class="header-anchor" href="#四、安全策略" aria-label="Permalink to &quot;四、安全策略&quot;">​</a></h2><h3 id="_4-1-不參戰" tabindex="-1">4.1 不參戰 <a class="header-anchor" href="#_4-1-不參戰" aria-label="Permalink to &quot;4.1 不參戰&quot;">​</a></h3><ul><li>不接受任何國家的雇傭/封臣邀請</li><li>保持全中立</li><li>好處：你的商隊不會被任何國家攻擊</li></ul><h3 id="_4-2-小部隊護航" tabindex="-1">4.2 小部隊護航 <a class="header-anchor" href="#_4-2-小部隊護航" aria-label="Permalink to &quot;4.2 小部隊護航&quot;">​</a></h3><ul><li>保持 20-30 人的小型護衛隊（打土匪夠用）</li><li>不要養大軍（沒必要，浪費錢）</li></ul><h3 id="_4-3-跑商注意" tabindex="-1">4.3 跑商注意 <a class="header-anchor" href="#_4-3-跑商注意" aria-label="Permalink to &quot;4.3 跑商注意&quot;">​</a></h3><ul><li>避免經過正在打仗的區域（商隊會被敵軍攻擊）</li><li>買保險：不要在一個區域集中所有工廠</li></ul><hr><h2 id="五、商人流終極目標" tabindex="-1">五、商人流終極目標 <a class="header-anchor" href="#五、商人流終極目標" aria-label="Permalink to &quot;五、商人流終極目標&quot;">​</a></h2><p>你玩到後期可以做到：</p><ul><li>擁有大陸上最多的現金</li><li>買下任何想買的裝備</li><li>僱傭兵幫你打你想打的仗</li><li>甚至直接用錢跟領主買下城鎮（需要高交易技能）</li></ul><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li><a href="./trade-routes.html">騎砍2 | 終極跑商路線圖</a></li><li><a href="./smithing-guide.html">騎砍2 | 鍛造系統深入指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',38)])])}const m=l(r,[["render",h]]);export{b as __pageData,m as default};
